        AND rqst.use_rs_cd = #{useRsCd}



        AND rqst.req_gbn_cd = #{reqGbnCd}



        AND rqst.doc_chng_yn = #{docChngYn}



        AND rqst.reqst_dat  >=  #{startDat}



        AND rqst.reqst_dat  <=  #{endDat}

SELECT rqst.acpt_dat AS acpt_dat, rqst.mgr_seq AS mgr_seq,
CASE WHEN ( SELECT COUNT ( * ) FROM xeus.crms_rqst_renew WHERE rqst_mgr_seq = rqst.mgr_seq ) != 0 AND ( SELECT COUNT ( * ) FROM xeus.crms_rqst_renew WHERE rqst_mgr_seq = rqst.mgr_seq ) = ( SELECT COUNT ( * ) FROM xeus.crms_rqst_renew WHERE rqst_mgr_seq = rqst.mgr_seq AND acpt_yn is not null ) THEN '완료' WHEN ( SELECT COUNT ( * ) FROM xeus.crms_rqst_renew WHERE rqst_mgr_seq = rqst.mgr_seq ) != 0 THEN '대기' ELSE null END AS renewAcptYn,
( SELECT file_nm FROM xeus.crms_trans_work WHERE rqst_mgr_seq = rqst.mgr_seq ORDER BY avi_mgr_seq ASC LIMIT 1 ) AS file_nm, ( SELECT COUNT(*) FROM xeus.crms_trans_work WHERE rqst_mgr_seq = rqst.mgr_seq) AS file_cnt, ( SELECT sec_st_dat FROM xeus.crms_trans_avi WHERE rqst_mgr_seq = rqst.mgr_seq ORDER BY mgr_seq ASC LIMIT 1 ) AS sec_st_dat, ( SELECT sec_ed_dat FROM xeus.crms_trans_avi WHERE rqst_mgr_seq = rqst.mgr_seq ORDER BY mgr_seq ASC LIMIT 1 ) AS sec_ed_dat,
(SELECT img_nm FROM xeus.crms_trans_rqst T1 LEFT JOIN xeus.crms_image_join T2 ON T1.mgr_seq = T2.rqst_mgr_seq LEFT JOIN xeus.crms_image T3 ON T2.img_mgr_seq = T3.mgr_seq WHERE T1.mgr_seq = rqst.mgr_seq ORDER BY T3.mgr_seq ASC LIMIT 1) AS img_nm, (SELECT COUNT( * ) FROM xeus.crms_trans_rqst T1 LEFT JOIN xeus.crms_image_join T2 ON T1.mgr_seq = T2.rqst_mgr_seq LEFT JOIN xeus.crms_image T3 ON T2.img_mgr_seq = T3.mgr_seq WHERE T1.mgr_seq = rqst.mgr_seq) AS img_cnt,
split_part(rqst.cctv_list,';',3) AS crime_addr, split_part(rqst.cctv_list,';',1) AS camera_num, reqst_resn_rel.cde_nm AS reqst_resn_rel_cde_nm, '계정명' AS folder_nm, acpt_user_id_rel.office_nm, acpt_user_id_rel.user_nm, acpt_user_id_rel.mobile_num, acpt_user_id_rel.dept_nm, reqst_id_rel.office_nm AS rqst_office_nm, reqst_id_rel.user_nm AS rqst_user_nm, reqst_id_rel.mobile_num AS rqst_mobile_num, reqst_id_rel.dept_nm AS rqst_dept_nm, '47977' AS reg_num, rqst.proc_stat_cd AS proc_stat_cd, proc_stat_cd_rel.cde_nm AS proc_stat_cd_rel_cde_nm, rqst.doc_chng_yn, '관할서 구분' AS gwanhal, rqst.reqst_id AS reqst_id, rqst.reqst_dat AS reqst_dat, rqst.reqst_resn AS reqst_resn, rqst.reqst_detail AS reqst_detail, rqst.crime_typ AS crime_typ, rqst.doc_no AS doc_no, rqst.doc_file_nm AS doc_file_nm, rqst.doc_file_path AS doc_file_path, rqst.crime_loc AS crime_loc, rqst.cctv_list AS cctv_list, rqst.acpt_user_id AS acpt_user_id, rqst.rejt_typ AS rejt_typ, rqst.rejt_resn AS rejt_resn, rqst.fnsh_dat AS fnsh_dat, rqst.recv_mthd AS recv_mthd, rqst.use_rs_cd AS use_rs_cd, rqst.car_info, rqst.req_gbn_cd, reqst_id_rel.user_nm AS reqst_id_rel_cde_nm, crime_typ_rel.cde_nm AS crime_typ_rel_cde_nm, acpt_user_id_rel.user_nm AS acpt_user_id_rel_cde_nm, rejt_typ_rel.cde_nm AS rejt_typ_rel_cde_nm, recv_mthd_rel.cde_nm AS recv_mthd_rel_cde_nm, req_gbn_cd_rel.cde_nm AS req_gbn_cd_rel_cde_nm, use_rs_cd_rel.cde_nm AS use_rs_cd_rel_cde_nm, rqst.video_smy FROM xeus.crms_trans_rqst AS rqst LEFT JOIN ( SELECT crms_user.user_id, orgz.org_nm AS office_nm, crms_user.user_nm, crms_user.depart_nm AS dept_nm, crms_user.pos_nm, crms_user.tel_num, crms_user.mobile_num, crms_user.auth_stat_cd AS user_stat_cd FROM xeus.mt_usr_desc crms_user LEFT JOIN xeus.mt_orgz_desc orgz ON orgz.org_mgr_no = crms_user.org_mgr_no ) AS reqst_id_rel ON reqst_id_rel.user_id = rqst.reqst_id LEFT JOIN xeus.mt_cmm_cde AS reqst_resn_rel ON reqst_resn_rel.grp_cde = 'C50' AND reqst_resn_rel.cde_cde = rqst.reqst_resn LEFT JOIN xeus.mt_cmm_cde AS crime_typ_rel ON crime_typ_rel.grp_cde = 'C51' AND crime_typ_rel.cde_cde = rqst.crime_typ LEFT JOIN xeus.mt_cmm_cde AS proc_stat_cd_rel ON proc_stat_cd_rel.grp_cde = 'C52' AND proc_stat_cd_rel.cde_cde = rqst.proc_stat_cd LEFT JOIN ( SELECT crms_user.user_id, orgz.org_nm AS office_nm, crms_user.user_nm, crms_user.depart_nm AS dept_nm, crms_user.pos_nm, crms_user.tel_num, crms_user.mobile_num, crms_user.auth_stat_cd AS user_stat_cd FROM xeus.mt_usr_desc crms_user LEFT JOIN xeus.mt_orgz_desc orgz ON orgz.org_mgr_no = crms_user.org_mgr_no ) AS acpt_user_id_rel ON acpt_user_id_rel.user_id = rqst.acpt_user_id LEFT JOIN xeus.mt_cmm_cde AS rejt_typ_rel ON rejt_typ_rel.grp_cde = 'C53' AND rejt_typ_rel.cde_cde = rqst.rejt_typ LEFT JOIN xeus.mt_cmm_cde AS recv_mthd_rel ON recv_mthd_rel.grp_cde = 'C54' AND recv_mthd_rel.cde_cde = rqst.recv_mthd LEFT JOIN xeus.mt_cmm_cde AS use_rs_cd_rel ON use_rs_cd_rel.grp_cde = 'C55' AND use_rs_cd_rel.cde_cde = rqst.use_rs_cd LEFT JOIN xeus.mt_cmm_cde AS req_gbn_cd_rel ON req_gbn_cd_rel.grp_cde = 'C58' AND req_gbn_cd_rel.cde_cde = rqst.req_gbn_cd
LEFT JOIN xeus.crms_rqst_renew AS renew ON renew.rqst_mgr_seq = rqst.mgr_seq
AND rqst.mgr_seq::text LIKE '%'||#{mgrSeq}||'%'
AND rqst.reqst_id LIKE '%'||#{reqstId}||'%'
AND reqst_id_rel.user_nm LIKE '%'||#{userNm}||'%'
AND rqst.reqst_dat = #{reqstDat}
AND rqst.reqst_resn = #{reqstResn}
AND rqst.reqst_detail = #{reqstDetail}
AND rqst.crime_typ = #{crimeTyp}
AND rqst.doc_no = #{docNo}
AND rqst.doc_file_nm = #{docFileNm}
AND rqst.doc_file_path = #{docFilePath}
AND rqst.crime_loc = #{crimeLoc}
AND rqst.cctv_list = #{cctvList}
AND rqst.proc_stat_cd = #{procStatCd}
AND rqst.acpt_user_id LIKE '%'||#{acptUserId}||'%'
AND rqst.acpt_dat = #{acptDat}
AND rqst.rejt_typ = #{rejtTyp}
AND rqst.rejt_resn = #{rejtResn}
AND rqst.fnsh_dat = #{fnshDat}
AND rqst.recv_mthd = #{recvMthd}
AND rqst.use_rs_cd = #{useRsCd}
AND rqst.req_gbn_cd = #{reqGbnCd}
AND rqst.doc_chng_yn = #{docChngYn}
AND rqst.reqst_dat >= #{startDat}
AND rqst.reqst_dat <= #{endDat}
GROUP BY rqst.mgr_seq, reqst_resn_rel_cde_nm, acpt_user_id_rel.office_nm, acpt_user_id_rel.user_nm, acpt_user_id_rel.mobile_num, acpt_user_id_rel.dept_nm, reqst_id_rel.office_nm ,reqst_id_rel.user_nm, reqst_id_rel.mobile_num,reqst_id_rel.dept_nm, proc_stat_cd_rel.cde_nm, crime_typ_rel.cde_nm, rejt_typ_rel.cde_nm, recv_mthd_rel.cde_nm, req_gbn_cd_rel.cde_nm, use_rs_cd_rel.cde_nm
HAVING (COUNT(renew.mgr_seq) <> 0 AND COUNT(renew.mgr_seq) > COUNT(renew.acpt_yn)) OR rqst.proc_stat_cd =#{procStatCdOrRenew}
${sortCol} ${sortTyp} NULLS LAST
rqst.mgr_seq DESC
rqst.mgr_seq DESC
LIMIT ${limit} OFFSET ${offset}

SELECT rqst.mgr_seq AS mgr_seq, rqst.reqst_id AS reqst_id, rqst.reqst_dat AS reqst_dat, rqst.reqst_resn AS reqst_resn, rqst.reqst_detail AS reqst_detail
        , rqst.crime_typ AS crime_typ, rqst.doc_no AS doc_no, rqst.doc_file_nm AS doc_file_nm, rqst.doc_file_path As doc_file_path, rqst.crime_loc AS crime_loc
        , rqst.cctv_list AS cctv_list, rqst.proc_stat_cd AS proc_stat_cd, rqst.acpt_user_id AS acpt_user_id, rqst.acpt_dat AS acpt_dat, rqst.rejt_typ AS rejt_typ
        , rqst.rejt_resn AS rejt_resn, rqst.fnsh_dat AS fnsh_dat, rqst.recv_mthd AS recv_mthd, rqst.use_rs_cd AS use_rs_cd, rqst.car_info, rqst.req_gbn_cd, rqst.doc_chng_yn
        , rqst.video_smy
        , reqst_id_rel.user_nm AS reqst_id_rel_cde_nm, reqst_resn_rel.cde_nm AS reqst_resn_rel_cde_nm, crime_typ_rel.cde_nm AS crime_typ_rel_cde_nm
        , proc_stat_cd_rel.cde_nm AS proc_stat_cd_rel_cde_nm, acpt_user_id_rel.user_nm AS acpt_user_id_rel_cde_nm, rejt_typ_rel.cde_nm AS rejt_typ_rel_cde_nm
        , recv_mthd_rel.cde_nm AS recv_mthd_rel_cde_nm, use_rs_cd_rel.cde_nm AS use_rs_cd_rel_cde_nm, req_gbn_cd_rel.cde_nm AS req_gbn_cd_rel_cde_nm

FROM xeus.crms_trans_rqst AS rqst

LEFT JOIN (
        SELECT crms_user.user_id,
