        FROM xeus.mt_usr_desc crms_user
        LEFT JOIN xeus.mt_orgz_desc orgz ON orgz.org_mgr_no = crms_user.org_mgr_no
        )  AS reqst_id_rel         ON reqst_id_rel.user_id = rqst.reqst_id
LEFT JOIN xeus.mt_cmm_cde   AS reqst_resn_rel       ON reqst_resn_rel.grp_cde = 'C50' AND reqst_resn_rel.cde_cde = rqst.reqst_resn
LEFT JOIN xeus.mt_cmm_cde   AS crime_typ_rel        ON crime_typ_rel.grp_cde = 'C51' AND crime_typ_rel.cde_cde = rqst.crime_typ
LEFT JOIN xeus.mt_cmm_cde   AS proc_stat_cd_rel     ON proc_stat_cd_rel.grp_cde = 'C52' AND proc_stat_cd_rel.cde_cde = rqst.proc_stat_cd
LEFT JOIN (
