        FROM xeus.mt_usr_desc crms_user
        LEFT JOIN xeus.mt_orgz_desc orgz ON orgz.org_mgr_no = crms_user.org_mgr_no
        )  AS acpt_user_id_rel     ON acpt_user_id_rel.user_id = rqst.acpt_user_id
LEFT JOIN xeus.mt_cmm_cde   AS rejt_typ_rel         ON rejt_typ_rel.grp_cde = 'C53' AND rejt_typ_rel.cde_cde = rqst.rejt_typ
LEFT JOIN xeus.mt_cmm_cde   AS recv_mthd_rel        ON recv_mthd_rel.grp_cde = 'C54' AND recv_mthd_rel.cde_cde = rqst.recv_mthd
LEFT JOIN xeus.mt_cmm_cde   AS use_rs_cd_rel        ON use_rs_cd_rel.grp_cde = 'C55' AND use_rs_cd_rel.cde_cde = rqst.use_rs_cd
LEFT JOIN xeus.mt_cmm_cde   AS req_gbn_cd_rel       ON req_gbn_cd_rel.grp_cde = 'C58' AND req_gbn_cd_rel.cde_cde = rqst.req_gbn_cd






