SELECT avi.cctv_mgr_no as avi_cctv_mgr_no , cctv._annox as cctv_annox , cctv._annoy as cctv_annoy , count(*) as cctv_count
FROM xeus.crms_trans_rqst as rqst
LEFT JOIN xeus.crms_trans_avi AS avi ON avi.rqst_mgr_seq = rqst.mgr_seq JOIN xeus.asset_cctv AS cctv ON cctv.mgr_no = avi.cctv_mgr_no LEFT JOIN xeus.mt_cmm_cde AS code ON code.cde_cde = rqst.crime_typ AND code.grp_cde = 'C51'
AND rqst.reqst_dat >= #{startDat}
