 INSERT INTO xeus.crms_trans_rqst (
 	mgr_seq, reqst_id, reqst_dat, reqst_resn, reqst_detail, crime_typ
 	, cctv_list, proc_stat_cd, recv_mthd
 	, doc_no, doc_file_nm, doc_file_path
 	, crime_loc
 	, acpt_user_id, acpt_dat, rejt_typ, rejt_resn
 	, fnsh_dat, use_rs_cd, req_gbn_cd
 	, car_info, video_smy
	)
 VALUES (
 	#{mgrSeq}::numeric, #{reqstId}, #{reqstDat}, #{reqstResn}, #{reqstDetail}, #{crimeTyp}
 	, #{cctvList}, #{procStatCd}, #{recvMthd}
 	, #{docNo}, #{docFileNm}, #{docFilePath}
 	, #{crimeLoc}
 	, #{acptUserId}, #{acptDat}, #{rejtTyp}, #{rejtResn}
 	, #{fnshDat}, #{useRsCd}, #{reqGbnCd}
 	, #{carInfo}, #{videoSmy}
	)

